import { Injectable, signal, effect, computed } from '@angular/core';
import { SignalType } from './types';

export const NOTIFICATIONS_ENABLED_KEY = 'cygnus_notifications_enabled';
export const NOTIFICATION_CONFIDENCE_THRESHOLD_KEY = 'cygnus_notif_confidence_threshold';
export const DISABLED_SIGNAL_TYPES_NOTIFICATIONS_KEY = 'cygnus_disabled_signal_types_notifs';

@Injectable({
  providedIn: 'root'
})
export class UserPrefsService {
  readonly notificationsEnabled = signal<boolean>(this.loadBoolean(NOTIFICATIONS_ENABLED_KEY, true));
  readonly notificationConfidenceThreshold = signal<number>(this.loadNumber(NOTIFICATION_CONFIDENCE_THRESHOLD_KEY, 0));
  readonly disabledSignalTypesForNotifications = signal<Set<SignalType>>(this.loadSet<SignalType>(DISABLED_SIGNAL_TYPES_NOTIFICATIONS_KEY));

  constructor() {
    effect(() => {
      localStorage.setItem(NOTIFICATIONS_ENABLED_KEY, String(this.notificationsEnabled()));
    });
    effect(() => {
      localStorage.setItem(NOTIFICATION_CONFIDENCE_THRESHOLD_KEY, String(this.notificationConfidenceThreshold()));
    });
    effect(() => {
      localStorage.setItem(DISABLED_SIGNAL_TYPES_NOTIFICATIONS_KEY, JSON.stringify(Array.from(this.disabledSignalTypesForNotifications())));
    });
  }

  loadBoolean(key: string, defaultValue: boolean): boolean {
    const value = localStorage.getItem(key);
    return value === null ? defaultValue : value === 'true';
  }

  loadNumber(key: string, defaultValue: number): number {
    const value = localStorage.getItem(key);
    return value === null ? defaultValue : Number(value);
  }

  loadSet<T extends string | number>(key: string): Set<T> {
    const value = localStorage.getItem(key);
    return value === null ? new Set<T>() : new Set<T>(JSON.parse(value));
  }

  toggleNotifications() {
    this.notificationsEnabled.update(current => !current);
  }

  setNotificationConfidenceThreshold(threshold: number) {
    this.notificationConfidenceThreshold.set(threshold);
  }

  toggleSignalTypeNotification(signalType: SignalType) {
    this.disabledSignalTypesForNotifications.update(current => {
      const next = new Set(current);
      if (next.has(signalType)) {
        next.delete(signalType);
      } else {
        next.add(signalType);
      }
      return next;
    });
  }
}
