type SettingsTab = 'DATA' | 'INTERFACE' | 'NOTIFICATIONS' | 'ACCESSIBILITY';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [
    CommonModule, 
    IntelPanelComponent,
    MarketGridComponent,
    SignalFeedComponent,
    TokenDetailComponent,
    SyncIndicatorComponent,
    LogoComponent,
    AlgorithmDocsComponent,
    AlgorithmIconComponent,
    PerformanceDashboardComponent,
    NotificationListComponent
  ],
  templateUrl: './app.component.html',
})
export class AppComponent implements OnDestroy {
  public stateService = inject(TokenStateService);
  private dataService = inject(MarketDataService);
  public prefs = inject(UserPrefsService);
  private document = inject(DOCUMENT) as Document;
  private elementRef = inject(ElementRef);
  private webSocketService = inject(WebSocketService);
  private liveDataSource = inject(LiveDataSource);
  private simulationDataSource = inject(SimulationDataSource);
  private performanceTracker = inject(PerformanceTrackerService);

  // Expose signals for template
  tokens = this.stateService.tokens;
  regime = this.stateService.marketRegime;
  activeSignals = this.stateService.filteredSignals;
  selectedTokenSymbol = this.stateService.selectedTokenSymbol;
  marketSummary = this.stateService.marketSummary;

  btcReference = computed(() => {
    const btc = this.stateService.btcToken();
    if (!btc) return null;
    return {
      price: btc.price,
      change24h: btc.change24h ?? 0
    };
  });

  // Heartbeat Signals
  timerProgress = this.dataService.timerProgress;
  isUpdating = this.dataService.isUpdating;

  // Data Source Status
  webSocketStatus = this.webSocketService.status;
  apiStatus = this.liveDataSource.apiStatus;

  // Real-time clock
  currentTime = signal(new Date());
  private clockInterval: any;

  webSocketLinkStatus = computed(() => {
    const wsStatus = this.webSocketStatus();
    const provider = this.prefs.webSocketProvider();
    const providerName = provider === 'COINCAP' ? 'CoinCap' : 'Bitstamp';

    switch (wsStatus) {
      case 'CONNECTED':
        return { text: 'LIVE', color: 'text-blue-500 dark:text-blue-400', dotColor: 'bg-blue-500', pulse: true, title: `Receiving real-time price updates from ${providerName} via WebSocket.` };
      case 'CONNECTING':
        return { text: 'CONN...', color: 'text-yellow-600 dark:text-amber-400', dotColor: 'bg-yellow-500 dark:bg-amber-500', pulse: true, title: `Attempting to establish ${providerName} WebSocket connection.` };
      case 'ERROR':
        return { text: 'ERROR', color: 'text-red-500', dotColor: 'bg-red-500', pulse: true, title: `${providerName} WebSocket connection error.` };
      default:
        return { text: 'OFFLINE', color: 'text-slate-500', dotColor: 'bg-slate-500', pulse: false, title: `${providerName} WebSocket is disconnected.` };
    }
  });

  apiLinkStatus = computed(() => {
    const apiStatus = this.apiStatus();
    const provider = this.prefs.apiProvider();
    const providerName = provider === 'COINGECKO' ? 'CoinGecko' : 'CoinMarketCap';
    const cmcKey = this.prefs.coinMarketCapApiKey();

    if (provider === 'COINMARKETCAP' && !cmcKey.trim()) {
      return { text: 'KEY MISSING', color: 'text-yellow-600 dark:text-amber-400', dotColor: 'bg-yellow-500 dark:bg-amber-500', pulse: false, title: 'Please enter a CoinMarketCap API key in System Config.' };
    }

    if(this.isUpdating()) {
        return { text: 'FETCHING', color: 'text-purple-500 dark:text-purple-400', dotColor: 'bg-purple-500', pulse: true, title: `Fetching latest market data from ${providerName} via API.` };
    }
    switch (apiStatus) {
      case 'SUCCESS':
        return { text: 'OK', color: 'text-green-500 dark:text-teal-400', dotColor: 'bg-green-500 dark:bg-teal-500', pulse: false, title: `Last ${providerName} API poll was successful.` };
      case 'ERROR':
        return { text: 'FAIL', color: 'text-red-500', dotColor: 'bg-red-500', pulse: false, title: `Last ${providerName} API poll failed.` };
      default: // IDLE
        return { text: 'IDLE', color: 'text-slate-500', dotColor: 'bg-slate-500', pulse: false, title: `${providerName} API is idle, awaiting next poll.` };
    }
  });

  dataLinkStatus = computed(() => {
    const mode = this.prefs.dataSourceMode();
    if (mode === 'SIMULATION') {
      return { text: 'SIMULATION', color: 'text-green-500 dark:text-teal-400', dotColor: 'bg-green-500 dark:bg-teal-500', pulse: false, title: 'Using internal simulated market data.' };
    }
    // Fallback for any other modes or unexpected states
    return { text: 'OFFLINE', color: 'text-slate-500', dotColor: 'bg-slate-500', pulse: false, title: 'Data source is offline or not yet connected.' };
  });

  terminalId = Math.random().toString(36).substring(7).toUpperCase();

  // Modal States
  showSettings = signal(false);
  activeSettingsTab = signal<SettingsTab>('DATA');
  showDocs = signal(false);
  showPerformanceAudit = signal(false);
  showWatchlistEditor = signal(false);

  // BTC Detail Modal State
  showBtcDetail = signal(false);
  isFetchingBtcDetail = signal(false);

  // Watchlist Editor State
  tokenSearchTerm = signal('');
  tokenSuggestions = signal<TokenDefinition[]>([]);
  isSearching = signal(false);
  private searchTimeout: any;
  private draggedSymbol: string | null = null;

  // API Key State
  apiKeySaved = signal(false);
  private apiKeySaveTimeout: any;
  cmcApiKeyValidation = signal<'VALID' | 'INVALID' | 'UNTESTED'>('UNTESTED');
  private readonly CMC_API_KEY_REGEX = /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$/;

  // Notification settings UI
  public readonly configurableSignalTypes: { type: SignalType; name: string; icon: AlgoIconType }[] = [
    { type: SignalType.BURST_HUNTER, name: 'Burst Hunter', icon: 'BURST_HUNTER' },
    { type: SignalType.VOLATILITY_SQUEEZE, name: 'Volatility Squeeze', icon: 'VOLATILITY_SQUEEZE' },
    { type: SignalType.NEWS_SPIKE, name: 'News Spike', icon: 'NEWS_SPIKE' },
    { type: SignalType.GAIN_LOCK, name: 'Gain Lock', icon: 'GAIN_LOCK' },
    { type: SignalType.TREND_VECTOR, name: 'Trend Vector', icon: 'TREND_VECTOR' },
    { type: SignalType.HYPE_PULSE_BUY, name: 'Hype Pulse', icon: 'HYPE_PULSE' },
    { type: SignalType.SUPPORT_BOUNCE, name: 'Support Bounce', icon: 'PATTERN_SCANNER' },
    { type: SignalType.STABLE_ANCHOR, name: 'Stable Anchor', icon: 'STABLE_ANCHOR' },
    { type: SignalType.VENUE_SHIELD, name: 'Venue Shield', icon: 'VENUE_SHIELD' },
    { type: SignalType.JERRY_REVERSION, name: 'Jerry Reversion', icon: 'JERRY_REVERSION' },
  ];

  constructor() {
    effect(() => {
      const theme = this.prefs.theme();
      const isDark = theme === 'DARK' || theme === 'MONOKAI';

      this.document.documentElement.classList.toggle('dark', isDark);
      this.document.documentElement.classList.toggle('plasma', theme === 'PLASMA');
      this.document.documentElement.classList.toggle('mint', theme === 'MINT');
      this.document.documentElement.classList.toggle('daybreak', theme === 'DAYBREAK');
      this.document.documentElement.classList.toggle('winxp', theme === 'WIN_XP');
      this.document.documentElement.classList.toggle('monokai', theme === 'MONOKAI');
    });

    effect(() => {
      const key = this.prefs.coinMarketCapApiKey();
      this.validateCmcApiKey(key);
    });

    this.clockInterval = setInterval(() => this.currentTime.set(new Date()), 1000);
  }

  ngOnDestroy() {
    clearInterval(this.clockInterval);
    clearTimeout(this.apiKeySaveTimeout);
  }

  private validateCmcApiKey(key: string) {
    const trimmedKey = key.trim();
    if (!trimmedKey) {
        this.cmcApiKeyValidation.set('UNTESTED');
        return;
    }
    if (this.CMC_API_KEY_REGEX.test(trimmedKey)) {
        this.cmcApiKeyValidation.set('VALID');
    } else {
        this.cmcApiKeyValidation.set('INVALID');
    }
  }

  // --- Modal Toggles ---
  toggleSettings() { this.showSettings.update(v => !v); }
  toggleDocs() { this.showDocs.update(v => !v); }
  togglePerformanceAudit() { this.showPerformanceAudit.update(v => !v); }

  toggleWatchlistEditor() {
    this.showWatchlistEditor.update(v => !v);
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  async toggleBtcDetail() {
    const isOpening = !this.showBtcDetail();
    this.showBtcDetail.set(isOpening);

    // Fetch full data only when opening and if it's not already loaded OR has insufficient history
    const btc = this.stateService.btcToken();
    if (isOpening && (!btc || btc.priceHistory.length < 50)) {
      this.isFetchingBtcDetail.set(true);
      try {
        let btcData: Token | null = null;
        if (this.prefs.dataSourceMode() === 'SIMULATION') {
          await new Promise(res => setTimeout(res, 250)); // Simulate network
          btcData = this.simulationDataSource.getBtcDetail();
        } else {
          // Use CoinGecko for detailed chart data regardless of API provider choice
          btcData = await this.liveDataSource.fetchBtcDetail();
        }
        this.stateService.setBtcToken(btcData);
      } finally {
        this.isFetchingBtcDetail.set(false);
      }
    }
  }

  // --- Watchlist Management ---
  updateSearchTerm(event: Event) {
    const val = (event.target as HTMLInputElement).value;
    this.tokenSearchTerm.set(val);

    clearTimeout(this.searchTimeout);
    if (!val.trim()) {
      this.tokenSuggestions.set([]);
      this.isSearching.set(false);
      return;
    }

    this.isSearching.set(true);
    this.searchTimeout = setTimeout(async () => {
      const results = await this.dataService.searchTokens(val);
      const currentSymbols = new Set(this.tokens().map(t => t.symbol.toUpperCase()));
      const filtered = results.filter(r => !currentSymbols.has(r.symbol.toUpperCase()));
      this.tokenSuggestions.set(filtered);
      this.isSearching.set(false);
    }, 300); 
  }

  handleAddToken(suggestion: TokenDefinition) {
    this.dataService.addToken(suggestion.symbol, suggestion.cgId, suggestion.name, suggestion.imageUrl);
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  handleManualAdd(term: string) {
    if(!term) return;
    const suggestions = this.tokenSuggestions();
    const match = suggestions.length > 0 ? suggestions[0] : { symbol: term };
    this.handleAddToken(match);
  }

  handleRemoveToken(symbol: string) {
    this.dataService.removeToken(symbol);
  }

  handleReorder(event: { fromSymbol: string; toSymbol: string }) {
    this.dataService.reorderTokens(event.fromSymbol, event.toSymbol);
  }

  // --- Grid/Detail Interaction ---
  handleTokenSelect(symbol: string) {
    this.stateService.toggleSelectedToken(symbol);
  }

  deselectToken() {
    this.stateService.clearSelection();
  }

  // --- Layout Focus ---
  toggleFocus(id: WidgetId) {
    this.prefs.setFocus(id);
  }

  // --- Settings ---
  handleCmcApiKeyInput(event: Event) {
    const value = (event.target as HTMLInputElement).value;
    this.prefs.setCoinMarketCapApiKey(value);

    this.apiKeySaved.set(true);
    clearTimeout(this.apiKeySaveTimeout);
    this.apiKeySaveTimeout = setTimeout(() => {
      this.apiKeySaved.set(false);
    }, 2000);
  }

  handleConfidenceChange(event: Event) {
    const value = parseInt((event.target as HTMLInputElement).value, 10);
    this.prefs.setNotificationConfidenceThreshold(value);
  }

  isSignalNotificationEnabled(type: SignalType): boolean {
    return !this.prefs.disabledSignalTypesForNotifications().has(type);
  }

  toggleSignalNotification(type: SignalType) {
    // Special handling for Hype Pulse, which has BUY and SELL types
    if (type === SignalType.HYPE_PULSE_BUY || type === SignalType.HYPE_PULSE_SELL) {
      const isDisabled = this.prefs.disabledSignalTypesForNotifications().has(SignalType.HYPE_PULSE_BUY);
      this.prefs.setSignalTypeNotification(SignalType.HYPE_PULSE_BUY, isDisabled); // if it was disabled, enable it
      this.prefs.setSignalTypeNotification(SignalType.HYPE_PULSE_SELL, isDisabled);
    } else {
      this.prefs.toggleSignalTypeNotification(type);
    }
  }

  // --- Drag and Drop Handlers (for Modal) ---
  onDragStart(event: DragEvent, symbol: string) {
    this.draggedSymbol = symbol;
    (event.target as HTMLElement).classList.add('dragging-item');
    if (event.dataTransfer) event.dataTransfer.effectAllowed = 'move';
  }

  onDragOver(event: DragEvent) { event.preventDefault(); }

  onDragEnter(event: DragEvent) {
    const target = (event.currentTarget as HTMLElement);
    if (target && this.draggedSymbol) target.classList.add('drag-over-indicator');
  }

  onDragLeave(event: DragEvent) {
    (event.currentTarget as HTMLElement).classList.remove('drag-over-indicator');
  }

  onDrop(event: DragEvent, toSymbol: string) {
    event.preventDefault();
    if (this.draggedSymbol && this.draggedSymbol !== toSymbol) {
      this.handleReorder({ fromSymbol: this.draggedSymbol, toSymbol });
    }
    this.cleanupDragStyles();
  }

  onDragEnd(event: DragEvent) {
    this.cleanupDragStyles();
  }

  private cleanupDragStyles() {
    this.draggedSymbol = null;
    const nativeEl = this.elementRef.nativeElement;
    nativeEl.querySelectorAll('.dragging-item').forEach((el: HTMLElement) => el.classList.remove('dragging-item'));
    nativeEl.querySelectorAll('.drag-over-indicator').forEach((el: HTMLElement) => el.classList.remove('drag-over-indicator'));
  }
}

import { Injectable, signal } from '@angular/core';
import { Notification, AlgoIconType } from './types';

@Injectable({
  providedIn: 'root'
})
export class NotificationService {
  readonly notifications = signal<Notification[]>([]);
  private readonly NOTIFICATION_TTL = 6000; // 6 seconds

  show(title: string, message: string, type: 'success' | 'info' | 'warning' | 'danger', icon: AlgoIconType | 'INFO') {
    const newNotification: Notification = {
      id: Date.now(),
      title,
      message,
      type,
      icon
    };

    this.notifications.update(current => {
        // Limit to 3 notifications on screen at once for usability
        const limited = current.slice(0, 2); 
        return [newNotification, ...limited];
    });

    setTimeout(() => {
      this.remove(newNotification.id);
    }, this.NOTIFICATION_TTL);
  }

  remove(id: number) {
    this.notifications.update(current => current.filter(n => n.id !== id));
  }
}

import { Injectable, signal, computed, inject, effect } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime, PriceAlert, AlgoIconType, HistoryPoint } from './types';
import { MathUtils } from './math-utils';
import * as d3 from 'd3';
import { NotificationService } from './notification.service';
import { GeminiService } from './gemini.service';
import { UserPrefsService } from './user-prefs.service';

export interface PriceUpdateInfo {
  symbol: string;
  direction: 'up' | 'down' | 'same';
}

@Injectable({
  providedIn: 'root'
})
export class TokenStateService {
  private notificationService = inject(NotificationService);
  private geminiService = inject(GeminiService);
  private prefs = inject(UserPrefsService);

  // --- CONFIG ---
  private readonly SIGNAL_TTL = 30000; // 30 seconds

  // --- STATE ---
  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });
  readonly selectedTokenSymbol = signal<string | null>(null);
  readonly priceAlerts = signal<Map<string, PriceAlert>>(new Map());
  readonly activeSignals = signal<Signal[]>([]);
  readonly btcToken = signal<Token | null>(null);

  // For UI flash effect on real-time price updates
  readonly lastPriceUpdate = signal<PriceUpdateInfo | null>(null);
  private lastUpdateTimeout: any;

  constructor() {
    // This effect runs the synchronous signal generation on every data tick.
    effect(() => {
        this.tokens(); // Establish dependency
        this._updateSyncSignals();
    });
  }

  // --- COMPUTED DERIVATIONS ---

  readonly filteredSignals = computed(() => {
    const signals = this.activeSignals();
    const selected = this.selectedTokenSymbol();
    if (!selected) return signals;
    return signals.filter(s => s.tokenSymbol === selected);
  });

  readonly marketSummary = computed(() => {
    const summary = { advancing: 0, declining: 0, unchanged: 0 };
    this.tokens().forEach(token => {
        if (token.priceHistory.length < 2) {
            summary.unchanged++;
            return;
        }
        const currentPrice = token.price;
        const prevPrice = token.priceHistory[token.priceHistory.length - 2].value;
        if (currentPrice > prevPrice) summary.advancing++;
        else if (currentPrice < prevPrice) summary.declining++;
        else summary.unchanged++;
    });
    return summary;
  });

  // --- ACTIONS ---

  updateTokens(newTokens: Token[]) {
    this.tokens.set(newTokens);
    this.updateRegime(newTokens);
  }

  setBtcToken(token: Token | null) {
    this.btcToken.set(token);
  }

  updateBtcToken(summary: { price: number; change24h?: number }) {
    this.btcToken.update(current => {
      // If BTC token doesn't exist, create it from the summary.
      if (!current) {
        return {
          symbol: 'BTC',
          name: 'Bitcoin',
          price: summary.price,
          change24h: summary.change24h ?? 0,
          priceHistory: [{ time: Date.now(), value: summary.price }],
          // Dummy data for fields not in summary
          entryPrice: 0,
          volume: 0,
          yield: 0,
          volumeHistory: [],
          liquidityDepth: 0,
          cgId: 'bitcoin',
          imageUrl: 'https://assets.coingecko.com/coins/images/1/large/bitcoin.png'
        };
      }

      // If it exists, update it.
      return {
        ...current,
        price: summary.price,
        change24h: summary.change24h ?? current.change24h,
        priceHistory: [...current.priceHistory, { time: Date.now(), value: summary.price }].slice(-60)
      };
    });
  }

  // Efficiently update multiple token prices from a batched WebSocket stream
  batchUpdateTokenPrices(updates: Map<string, number>) {
    // Handle BTC separately as it's not in the main watchlist
    if (updates.has('BTC')) {
      const newBtcPrice = updates.get('BTC')!;
      this.btcToken.update(current => {
        if (!current || newBtcPrice === current.price) return current;

        const oldPrice = current.price;
        const direction = newBtcPrice > oldPrice ? 'up' : 'down';
        this.triggerPriceFlash({ symbol: 'BTC', direction });

        return {
          ...current,
          price: newBtcPrice,
          priceHistory: [...current.priceHistory, { time: Date.now(), value: newBtcPrice }].slice(-60)
        };
      });
      updates.delete('BTC');
    }

    if (updates.size === 0) return;

    this.tokens.update(currentTokens => {
      let hasChanged = false;

      const updatedTokens = currentTokens.map(token => {
        if (updates.has(token.symbol)) {
          const newPrice = updates.get(token.symbol)!;
          if (token.price !== newPrice) {
            hasChanged = true;
            const oldPrice = token.price;
            const direction = newPrice > oldPrice ? 'up' : 'down';

            this.triggerPriceFlash({ symbol: token.symbol, direction });

            return {
              ...token,
              price: newPrice,
              priceHistory: [...token.priceHistory, { time: Date.now(), value: newPrice }].slice(-60)
            };
          }
        }
        return token;
      });

      return hasChanged ? updatedTokens : currentTokens;
    });
  }

  private triggerPriceFlash(info: PriceUpdateInfo) {
    clearTimeout(this.lastUpdateTimeout);
    this.lastPriceUpdate.set(info);
    this.lastUpdateTimeout = setTimeout(() => this.lastPriceUpdate.set(null), 750);
  }

  toggleSelectedToken(symbol: string) {
    this.selectedTokenSymbol.update(current => current === symbol ? null : symbol);
  }

  clearSelection() {
    this.selectedTokenSymbol.set(null);
  }

  setPriceAlert(symbol: string, targetPrice: number, condition: 'ABOVE' | 'BELOW') {
    if (!targetPrice || targetPrice <= 0) {
      this.removePriceAlert(symbol);
      return;
    }
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.set(symbol, { targetPrice, condition });
      return newAlerts;
    });
  }

  removePriceAlert(symbol: string) {
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.delete(symbol);
      return newAlerts;
    });
  }

  // --- SIGNAL GENERATION ENGINE ---

  private _updateSyncSignals(): void {
    // 1. Generate all signals that are valid for the current state.
    const liveSignals: Signal[] = [];
    this.tokens().forEach(token => {
      // FIX: Although TypeScript types should prevent this, adding a guard ensures malformed token objects don't crash the signal generation loop.
      if (!token) return;

      const tokenSignals = [
        this._generatePriceAlertSignal(token),
        this._generateBurstHunterSignal(token),
        this._generateGainLockSignal(token),
        this._generateHypePulseSignal(token),
        this._generateTrendVectorSignal(token),
        this._generateStableAnchorSignal(token),
        this._generateVenueShieldSignal(token),
        this._generateSupportBounceSignal(token),
        this._generateVolatilitySqueezeSignal(token),
        this._generateJerryReversionSignal(token)
      ].filter((s): s is Signal => s !== null);
      liveSignals.push(...tokenSignals);
    });

    const liveSignalMap = new Map<string, Signal>();
    liveSignals.forEach(s => liveSignalMap.set(`${s.tokenSymbol}:${s.type}`, s));

    this.activeSignals.update(currentSignals => {
      // 2. Refresh existing signals and identify those that are no longer live.
      const refreshedAndStaleSignals = currentSignals
        .filter(s => s.type !== SignalType.NEWS_SPIKE) // Don't process async signals here
        .map(existingSignal => {
          const key = `${existingSignal.tokenSymbol}:${existingSignal.type}`;
          const liveVersion = liveSignalMap.get(key);

          if (liveVersion) {
            // Signal is still live. Update its data, preserve its unique ID, and refresh its timestamp.
            liveSignalMap.delete(key); 
            return { ...liveVersion, id: existingSignal.id, timestamp: Date.now() }; 
          } else {
            // Signal is no longer live, return it as is to check its TTL.
            return existingSignal;
          }
        });

      // 3. Filter out stale signals that have exceeded their TTL.
      const activeOrGracePeriodSignals = refreshedAndStaleSignals.filter(s => 
        Date.now() - s.timestamp < this.SIGNAL_TTL
      );

      // 4. Add any brand new signals, ensuring they get a unique ID.
      const newSignals = Array.from(liveSignalMap.values()).map(s => ({
        ...s,
        id: `${s.tokenSymbol}:${s.type}:${Date.now()}`
      }));

      // 5. Trigger notifications for new signals, respecting user preferences
      newSignals.forEach(signal => {
        if (!this.prefs.notificationsEnabled()) return;
        if (signal.confidence < this.prefs.notificationConfidenceThreshold()) return;
        if (this.prefs.disabledSignalTypesForNotifications().has(signal.type)) return;

        // Price alerts are user-initiated, so they should always notify if they meet the conditions above.
        // Other notifications can be filtered based on user preferences.
        this.notificationService.show(
          `${signal.tokenSymbol}: ${this.formatSignalType(signal.type)}`,
          signal.message,
          signal.severity,
          this.getIconForSignal(signal.type)
        );
      });

      // 6. Re-integrate async signals and sort.
      const asyncSignals = currentSignals.filter(s => s.type === SignalType.NEWS_SPIKE);
      const finalSignals = [...activeOrGracePeriodSignals, ...newSignals, ...asyncSignals];
      return finalSignals.sort((a, b) => b.timestamp - a.timestamp);
    });
  }

  async triggerAsyncSignalGeneration() {
    const mode = this.prefs.dataSourceMode();
    if (mode === 'SIMULATION') {
      await this.runSimulatedNewsSpike();
    } else {
      await this.runLiveNewsSpikeCheck();
    }
  }

  private async runSimulatedNewsSpike() {
    await new Promise(resolve => setTimeout(resolve, 300 + Math.random() * 400));

    const currentTokens = this.tokens();
    if (currentTokens.length === 0 || Math.random() > 0.15) {
      return; // 15% chance per cycle
    }

    const randomToken = currentTokens[Math.floor(Math.random() * currentTokens.length)];
    const hasExistingSignal = this.activeSignals().some(s => s.tokenSymbol === randomToken.symbol && s.type === SignalType.NEWS_SPIKE);

    if (hasExistingSignal) {
      return;
    }

    const isPositiveNews = Math.random() > 0.5;
    const event = isPositiveNews ? "a strategic partnership" : "a potential exploit";
    const title = `Unconfirmed reports suggest ${randomToken.name} is involved in ${event}.`;
    const newSignal = this._generateNewsSpikeSignal(randomToken, title, '#');

    if (newSignal) {
      this.addNewsSpikeSignal(newSignal);
    }
  }

  private async runLiveNewsSpikeCheck() {
    const currentTokens = this.tokens();
    if (currentTokens.length === 0) return;

    // Check a small, random subset of tokens to avoid API spam.
    // FIX: Explicitly type `tokensToCheck` as `Token[]` to resolve incorrect type inference to `unknown[]`.
    const tokensToCheck: Token[] = this.getRandomSubset(currentTokens, 3);

    for (const token of tokensToCheck) {
      const hasExistingSignal = this.activeSignals().some(s => s.tokenSymbol === token.symbol && s.type === SignalType.NEWS_SPIKE);
      if (hasExistingSignal) {
        continue;
      }

      const newsResponse = await this.geminiService.checkForNewsSpike(token);
      if (newsResponse?.isSignificantNews && newsResponse.articleTitle) {
        const newSignal = this._generateNewsSpikeSignal(token, newsResponse.articleTitle, newsResponse.articleUrl);
        if (newSignal) {
          this.addNewsSpikeSignal(newSignal);
        }
      }
    }
  }

  private addNewsSpikeSignal(newSignal: Signal) {
    // Check notification preferences before showing
    if (this.prefs.notificationsEnabled() &&
        newSignal.confidence >= this.prefs.notificationConfidenceThreshold() &&
        !this.prefs.disabledSignalTypesForNotifications().has(newSignal.type)) {
      this.notificationService.show(
        `${newSignal.tokenSymbol}: ${this.formatSignalType(newSignal.type)}`,
        newSignal.message,
        newSignal.severity,
        this.getIconForSignal(newSignal.type)
      );
    }

    this.activeSignals.update(currentSignals => {
      const activeAsyncSignals = currentSignals
        .filter(s => s.type === SignalType.NEWS_SPIKE)
        .filter(s => Date.now() - s.timestamp < this.SIGNAL_TTL);
      const otherSignals = currentSignals.filter(s => s.type !== SignalType.NEWS_SPIKE);
      const combined = [...otherSignals, ...activeAsyncSignals, newSignal];
      return combined.sort((a, b) => b.timestamp - a.timestamp);
    });
  }

  private updateRegime(tokens: Token[]) {
    if (tokens.length === 0) return;
    const avgVol = tokens.reduce((acc, t) => {
        const history = t.priceHistory.slice(-10).map(p => p.value);
        if (history.length === 0) return acc;
        const vol = MathUtils.stdDev(history) / MathUtils.average(history);
        return acc + vol;
    }, 0) / tokens.length;

    const upMoves = tokens.filter(t => t.priceHistory.length > 1 && t.price > t.priceHistory[t.priceHistory.length - 2].value).length;
    const correlationFactor = Math.abs((upMoves / tokens.length) - 0.5) * 2; 

    let status: MarketRegime['status'] = 'NEUTRAL';
    if (avgVol > 0.015) status = 'VOLATILE'; 
    else if (correlationFactor > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH';
    else if (correlationFactor > 0.6 && upMoves < tokens.length / 2) status = 'BEARISH';

    this.marketRegime.set({ status, volatility: avgVol, correlation: correlationFactor });
  }

  // --- Individual Algorithm Implementations ---

  private _generateNewsSpikeSignal(token: Token, title: string, url?: string): Signal | null {
    return {
      id: `NEWS_SPIKE:${token.symbol}:${Date.now()}`, // Make ID unique
      timestamp: Date.now(),
      type: SignalType.NEWS_SPIKE,
      tokenSymbol: token.symbol,
      message: `NEWS: ${title}`,
      severity: 'warning',
      confidence: 95,
      meta: { url }
    };
  }

  private _generatePriceAlertSignal(token: Token): Signal | null {
    const alert = this.priceAlerts().get(token.symbol);
    if (!alert) return null;

    const conditionMet = 
      (alert.condition === 'ABOVE' && token.price > alert.targetPrice) ||
      (alert.condition === 'BELOW' && token.price < alert.targetPrice);

    if (conditionMet) {
      return {
        id: `PRICE_ALERT:${token.symbol}`,
        timestamp: Date.now(),
        type: SignalType.PRICE_ALERT,
        tokenSymbol: token.symbol,
        message: `Price crossed ${alert.condition.toLowerCase()} alert at $${alert.targetPrice.toFixed(4)}.`,
        severity: 'warning',
        confidence: 100 
      };
    }
    return null;
  }

  private _generateBurstHunterSignal(token: Token): Signal | null {
    const priceHistory = token.priceHistory.map(p => p.value);
    const volumeHistory = token.volumeHistory.map(p => p.value);
    const smaVol20 = MathUtils.sma(volumeHistory, 20);
    const sma20 = MathUtils.sma(priceHistory, 20);
    if (!smaVol20 || priceHistory.length < 3 || !sma20) return null;

    const lastPrice = priceHistory[priceHistory.length - 2];
    const prevLastPrice = priceHistory[priceHistory.length - 3];

    // FIX: Add a guard to prevent division-by-zero errors if historical price data is 0.
    if (!lastPrice || !prevLastPrice) return null;

    const priceChange = (token.price - lastPrice) / lastPrice;
    const prevPriceChange = (lastPrice - prevLastPrice) / prevLastPrice;
    const isAccelerating = priceChange > prevPriceChange;
    const ratio = token.volume / smaVol20;
    const inUptrend = token.price > sma20;

    if (ratio > 3.5 && priceChange > 0.02 && isAccelerating && inUptrend) {
      const marketSummary = this.marketSummary();
      let conf = Math.min(Math.round((ratio / 10) * 100), 85) + 5;
      const marketBreadth = marketSummary.advancing / (marketSummary.advancing + marketSummary.declining || 1);
      if (marketBreadth > 0.6) conf = Math.min(conf + 10, 99);

      return {
        id: `BURST:${token.symbol}`,
        timestamp: Date.now(),
        type: SignalType.BURST_HUNTER,
        tokenSymbol: token.symbol,
        message: `Macro-Confirmed Volume Burst: ${ratio.toFixed(1)}x normal.`,
        severity: 'success',
        confidence: conf
      };
    }
    return null;
  }

  private _generateGainLockSignal(token: Token): Signal | null {
    // FIX: Add a guard to prevent runtime errors if the token object is malformed or entryPrice is zero.
    // This addresses potential issues with unknown data types and prevents division-by-zero errors.
    if (!token || !token.symbol || token.entryPrice <= 0) return null;

    const profitMargin = (token.price - token.entryPrice) / token.entryPrice;
    const priceHistory = token.priceHistory.map(p => p.value);
    const sma10 = MathUtils.sma(priceHistory, 10);
    const sma50 = MathUtils.sma(priceHistory, 50);

    if (profitMargin > 1.0 && sma10 && sma50 && sma10 < sma50) {
       return {
          id: `LOCK:${token.symbol}`,
          timestamp: Date.now(),
          type: SignalType.GAIN_LOCK,
          tokenSymbol: token.symbol,
          message: `Take Profit: +${(profitMargin * 100).toFixed(0)}% gain with Momentum Death Cross.`,
          severity: 'warning',
          confidence: 90 
        };
    }
    return null;
  }

  private _generateHypePulseSignal(token: Token): Signal | null {
    const priceHistory = token.priceHistory.map(p => p.value);
    const rsi = MathUtils.rsi(priceHistory, 14);
    if (!rsi) return null;

    let overboughtThreshold = 70;
    const marketRegime = this.marketRegime();

    if (marketRegime.status === 'BULLISH') overboughtThreshold = 80;
    else if (marketRegime.status === 'BEARISH') overboughtThreshold = 60;

    if (rsi > overboughtThreshold) {
      const conf = Math.min(Math.round(((rsi - overboughtThreshold) / (100 - overboughtThreshold)) * 100) + 50, 95);
      return {
          id: `HYPE_BUY:${token.symbol}`,
          timestamp: Date.now(),
          type: SignalType.HYPE_PULSE_BUY,
          tokenSymbol: token.symbol,
          message: `Overbought (RSI > ${overboughtThreshold}): ${rsi.toFixed(0)}.`,
          severity: 'info',
          confidence: conf
      };
    }
    return null;
  }

  private _generateTrendVectorSignal(token: Token): Signal | null {
      const priceHistory = token.priceHistory.map(p => p.value);
      const historyShort = priceHistory.slice(-15);
      const regression = MathUtils.linearRegression(historyShort);
      const sma50 = MathUtils.sma(priceHistory, 50);
      const currentVolatility = this.marketRegime().volatility;
      const rSquaredThreshold = currentVolatility > 0.015 ? 0.75 : 0.60;

      if (regression && sma50 && regression.r2 > rSquaredThreshold && currentVolatility < 0.025) {
        const slopePercent = regression.m / token.price;
        if (Math.abs(slopePercent) > 0.005) {
           const direction = slopePercent > 0 ? 'UP' : 'DOWN';
           const isConfirmed = (direction === 'UP' && token.price > sma50) || (direction === 'DOWN' && token.price < sma50);

           if (isConfirmed) {
              const projected = token.price + (regression.m * 5); 
              const conf = 85 + Math.round(((regression.r2 - rSquaredThreshold) / (1.0 - rSquaredThreshold)) * 14);
              return {
                id: `VECTOR:${token.symbol}`,
                timestamp: Date.now(),
                type: SignalType.TREND_VECTOR,
                tokenSymbol: token.symbol,
                message: `Strong Trend Vector (R²=${regression.r2.toFixed(2)}): Projecting ${projected.toFixed(2)}`,
                severity: direction === 'UP' ? 'success' : 'danger',
                confidence: Math.min(conf, 99),
                meta: { projectedPrice: projected }
              };
           }
        }
      }
      return null;
  }

  private _generateStableAnchorSignal(token: Token): Signal | null {
      if (token.price <= 0) return null;
      const priceHistory = token.priceHistory.map(p => p.value);
      const volatility = MathUtils.stdDev(priceHistory.slice(-20)) / token.price; 
      if (volatility < 0.05 && token.yield > 5.0) {
         return {
            id: `ANCHOR:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.STABLE_ANCHOR,
            tokenSymbol: token.symbol,
            message: `Yield Safe Haven: ${token.yield.toFixed(2)}% APY.`,
            severity: 'success',
            confidence: 85
          };
      }
      return null;
  }

  private _generateVenueShieldSignal(token: Token): Signal | null {
      if (token.liquidityDepth < 1000000) { 
         return {
            id: `VENUE:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.VENUE_SHIELD,
            tokenSymbol: token.symbol,
            message: `High Slippage Risk: Low Liquidity.`,
            severity: 'danger',
            confidence: 100
          };
      }
      return null;
  }

  private _generateSupportBounceSignal(token: Token): Signal | null {
      const priceHistory = token.priceHistory.map(p => p.value);
      const volumeHistory = token.volumeHistory.map(p => p.value);
      const rsi = MathUtils.rsi(priceHistory, 14);
      if (priceHistory.length > 20 && volumeHistory.length > 2 && rsi && rsi < 65) {
         const recent = priceHistory.slice(-20);
         const minPrice = d3.min(recent) || 0;
         const current = token.price;
         const prev = priceHistory[priceHistory.length - 2];
         const volumeConf = token.volume > volumeHistory[volumeHistory.length - 2];

         if (current > prev && (current - minPrice) / minPrice < 0.05 && current > minPrice && volumeConf) {
            return {
              id: `SUPPORT_BOUNCE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.SUPPORT_BOUNCE,
              tokenSymbol: token.symbol,
              message: `Volume-Confirmed Bounce off 20-period low.`,
              severity: 'success',
              confidence: 75
            };
         }
      }
      return null;
  }

  private _generateVolatilitySqueezeSignal(token: Token): Signal | null {
      const priceHistory = token.priceHistory.map(p => p.value);
      const rsi = MathUtils.rsi(priceHistory, 14);
      const sma20 = MathUtils.sma(priceHistory, 20);
      if (priceHistory.length > 20 && rsi && rsi > 40 && rsi < 60) {
         const period = 20;
         const recent = priceHistory.slice(-period);
         const sma = sma20 || token.price;
         const stdDev = MathUtils.stdDev(recent);

         const upper = sma + (2 * stdDev);
         const lower = sma - (2 * stdDev);
         const bandwidth = (upper - lower) / sma;

         if (bandwidth < 0.025) {
            const conf = 80 + Math.round(((0.025 - bandwidth) / 0.025) * 19);
            return {
              id: `SQUEEZE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.VOLATILITY_SQUEEZE,
              tokenSymbol: token.symbol,
              message: `High-Compression Squeeze: (Bandwidth ${(bandwidth*100).toFixed(2)}%).`,
              severity: 'warning',
              confidence: Math.min(conf, 99)
            };
         }
      }
      return null;
  }

  private _generateJerryReversionSignal(token: Token): Signal | null {
    const marketRegime = this.marketRegime();
    const priceHistory = token.priceHistory.map(p => p.value);
    if ((marketRegime.status === 'NEUTRAL' || marketRegime.status === 'VOLATILE') && priceHistory.length > 20) {
      const sma20 = MathUtils.sma(priceHistory, 20);
      const stdDev20 = MathUtils.stdDev(priceHistory.slice(-20));
      const prevPrice = priceHistory[priceHistory.length - 2];
      const prevPrevPrice = priceHistory[priceHistory.length - 3];

      if (sma20 && stdDev20 && prevPrice && prevPrevPrice) {
        const currentVolatility = stdDev20 / token.price;
        const priceDeviation = (sma20 - token.price) / sma20;
        const isBelowMean = priceDeviation > 0.05;
        const isLowVolatility = currentVolatility < 0.10;
        const isReverting = token.price > prevPrice && prevPrice > prevPrevPrice;

        if (isBelowMean && isLowVolatility && isReverting) {
          let conf = 75;
          if (priceDeviation > 0.1) conf += 10;
          if (currentVolatility < 0.05) conf += 10;

          return {
            id: `JERRY:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.JERRY_REVERSION,
            tokenSymbol: token.symbol,
            message: `Confirmed Reversion: ${(priceDeviation * 100).toFixed(0)}% below mean.`,
            severity: 'success',
            confidence: Math.min(conf, 99)
          };
        }
      }
    }
    return null;
  }

  // --- Helpers ---
  private getRandomSubset<T>(arr: T[], size: number): T[] {
    const shuffled = [...arr].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, Math.min(size, arr.length));
  }

  private formatSignalType(type: SignalType): string {
    return type.replace(/_/g, ' ').replace('BUY', '').replace('SELL', '').trim();
  }

  private getIconForSignal(type: SignalType): AlgoIconType {
    if (type === SignalType.HYPE_PULSE_BUY || type === SignalType.HYPE_PULSE_SELL) {
      return 'HYPE_PULSE';
    }
    if (type === SignalType.PRICE_ALERT) {
      return 'GAIN_LOCK';
    }
    if (type === SignalType.SUPPORT_BOUNCE) {
      return 'PATTERN_SCANNER';
    }
    return type as AlgoIconType;
  }
}

import { Injectable, signal } from '@angular/core';
import { SignalType } from './types';

export type WidgetId = 'INTEL' | 'MARKET' | 'SIGNALS' | null;
export type DataSourceMode = 'SIMULATION' | 'LIVE';
export type ApiProvider = 'COINGECKO' | 'COINMARKETCAP';
export type WebSocketProvider = 'COINCAP' | 'BITSTAMP';
export type RefreshRate = 'HYPER' | 'AGGRESSIVE' | 'STANDARD' | 'SAFE'; // 5s, 30s, 60s, 120s
export type AppTheme = 'DARK' | 'DAYBREAK' | 'PLASMA' | 'MINT' | 'WIN_XP' | 'MONOKAI';
export type TimeFormat = '12H' | '24H';

const WATCHLIST_ORDER_KEY = 'cygnus_watchlist_order';
const COINMARKETCAP_API_KEY_KEY = 'cygnus_cmc_api_key';
const NOTIFICATIONS_ENABLED_KEY = 'cygnus_notifications_enabled';
const NOTIFICATION_CONFIDENCE_THRESHOLD_KEY = 'cygnus_notif_confidence_threshold';
const DISABLED_SIGNAL_TYPES_NOTIFICATIONS_KEY = 'cygnus_disabled_signal_types_notifs';

@Injectable({
  providedIn: 'root'
})
export class UserPrefsService {
  // Cognitive Settings
  readonly reducedMotion = signal<boolean>(false);

  // Appearance Settings
  readonly theme = signal<AppTheme>('DARK');
  readonly timeFormat = signal<TimeFormat>('24H');

  // Data Settings
  readonly dataSourceMode = signal<DataSourceMode>('SIMULATION');
  readonly apiProvider = signal<ApiProvider>('COINGECKO');
  readonly webSocketProvider = signal<WebSocketProvider>('COINCAP');
  readonly refreshRate = signal<RefreshRate>('STANDARD');
  readonly coinMarketCapApiKey = signal<string>(this.loadString(COINMARKETCAP_API_KEY_KEY, ''));
  readonly useSearchGrounding = signal<boolean>(false);

  // Notification Settings
  readonly notificationsEnabled = signal<boolean>(this.loadBoolean(NOTIFICATIONS_ENABLED_KEY, true));
  readonly notificationConfidenceThreshold = signal<number>(this.loadNumber(NOTIFICATION_CONFIDENCE_THRESHOLD_KEY, 0));
  readonly disabledSignalTypesForNotifications = signal<Set<SignalType>>(this.loadSet<SignalType>(DISABLED_SIGNAL_TYPES_NOTIFICATIONS_KEY));

  // Layout State (Focus Mode)
  readonly focusedWidget = signal<WidgetId>(null);

  // Watchlist State
  readonly watchlistOrder = signal<string[]>(this.loadArray<string>(WATCHLIST_ORDER_KEY));

  // --- Loaders with Type Safety ---
  private loadString(key: string, defaultValue: string): string {
    try {
      return localStorage.getItem(key) || defaultValue;
    } catch (e) {
      console.error(`Failed to load string from localStorage for key "${key}"`, e);
      return defaultValue;
    }
  }

  private loadBoolean(key: string, defaultValue: boolean): boolean {
    try {
      const stored = localStorage.getItem(key);
      return stored ? stored === 'true' : defaultValue;
    } catch (e) {
      console.error(`Failed to load boolean from localStorage for key "${key}"`, e);
      return defaultValue;
    }
  }

  private loadNumber(key: string, defaultValue: number): number {
    try {
      const stored = localStorage.getItem(key);
      return stored ? parseInt(stored, 10) : defaultValue;
    } catch (e) {
      console.error(`Failed to load number from localStorage for key "${key}"`, e);
      return defaultValue;
    }
  }

  private loadArray<T>(key: string): T[] {
    try {
      const stored = localStorage.getItem(key);
      return stored ? JSON.parse(stored) : [];
    } catch (e) {
      console.error(`Failed to load array from localStorage for key "${key}"`, e);
      return [];
    }
  }

  private loadSet<T>(key: string): Set<T> {
    try {
      const stored = localStorage.getItem(key);
      return stored ? new Set(JSON.parse(stored)) : new Set();
    } catch(e) {
      console.error(`Failed to load Set from localStorage for key "${key}"`, e);
      return new Set();
    }
  }

  // --- Savers ---
  private save(key: string, value: string | number | boolean) {
    try {
      localStorage.setItem(key, String(value));
    } catch (e) {
      console.error(`Failed to save to localStorage for key "${key}"`, e);
    }
  }

  private saveArray<T>(key: string, value: T[]) {
    try {
      localStorage.setItem(key, JSON.stringify(value));
    } catch (e) {
      console.error(`Failed to save array to localStorage for key "${key}"`, e);
    }
  }

  private saveSet<T>(key: string, value: Set<T>) {
    try {
      localStorage.setItem(key, JSON.stringify(Array.from(value)));
    } catch (e) {
      console.error(`Failed to save Set to localStorage for key "${key}"`, e);
    }
  }

  // --- Watchlist Order Persistence ---
  saveWatchlistOrder(symbols: string[]) {
    this.saveArray(WATCHLIST_ORDER_KEY, symbols);
    this.watchlistOrder.set(symbols);
  }

  // --- Other Methods ---
  toggleMotion() {
    this.reducedMotion.update(v => !v);
  }

  setTheme(theme: AppTheme) {
    this.theme.set(theme);
  }

  setTimeFormat(format: TimeFormat) {
    this.timeFormat.set(format);
  }

  setDataSourceMode(mode: DataSourceMode) {
    this.dataSourceMode.set(mode);
  }

  setApiProvider(provider: ApiProvider) {
    this.apiProvider.set(provider);
  }

  setWebSocketProvider(provider: WebSocketProvider) {
    this.webSocketProvider.set(provider);
  }

  setRefreshRate(rate: RefreshRate) {
    this.refreshRate.set(rate);
  }

  setCoinMarketCapApiKey(key: string) {
    this.coinMarketCapApiKey.set(key);
    this.save(COINMARKETCAP_API_KEY_KEY, key);
  }

  toggleSearchGrounding() {
    this.useSearchGrounding.update(v => !v);
  }

  setFocus(widgetId: WidgetId) {
    this.focusedWidget.update(current => current === widgetId ? null : widgetId);
  }

  clearFocus() {
    this.focusedWidget.set(null);
  }

  // --- Notification Preferences ---
  toggleNotifications() {
    this.notificationsEnabled.update(v => {
      const newValue = !v;
      this.save(NOTIFICATIONS_ENABLED_KEY, newValue);
      return newValue;
    });
  }

  setNotificationConfidenceThreshold(threshold: number) {
    this.notificationConfidenceThreshold.set(threshold);
    this.save(NOTIFICATION_CONFIDENCE_THRESHOLD_KEY, threshold);
  }

  setSignalTypeNotification(signalType: SignalType, enabled: boolean) {
    this.disabledSignalTypesForNotifications.update(currentSet => {
      const newSet = new Set(currentSet);
      if (enabled) {
        newSet.delete(signalType);
      } else {
        newSet.add(signalType);
      }
      this.saveSet(DISABLED_SIGNAL_TYPES_NOTIFICATIONS_KEY, newSet);
      return newSet;
    });
  }

  toggleSignalTypeNotification(signalType: SignalType) {
    const isDisabled = this.disabledSignalTypesForNotifications().has(signalType);
    this.setSignalTypeNotification(signalType, isDisabled);
  }
}

