import { Injectable, inject, signal } from '@angular/core';
import { Token, HistoryPoint } from '../types';
import { TokenDefinition } from '../market-data.service';
import { NotificationService } from '../notification.service';
import { UserPrefsService } from '../user-prefs.service';
import { MarketDataService } from '../market-data.service';
import { interval, Observable, of, startWith, switchMap, takeWhile, tap } from 'rxjs';
import {LiveTokenData, SourceData} from "./types";
import {HttpClient} from "@angular/common/http";
import {environment} from "../../../environments/environment";

@Injectable({
  providedIn: 'root'
})
export class LiveDataSource implements SourceData {
  private readonly marketDataService = inject(MarketDataService);
  private readonly notificationService = inject(NotificationService);
  private readonly userPrefsService = inject(UserPrefsService);
  private readonly http = inject(HttpClient);
  public tokens = signal<Token[]>([]);

  private API_URL = environment.apiUrl;

  constructor() {
    this.refreshTokens();
  }

  async refreshTokens() {
    this.getInitialTokenList().then(r => {
      this.tokens.set(r);
    });
  }

  async getInitialTokenList(): Promise<Token[]> {
    const marketData = await this.marketDataService.getMarketData();
    return marketData.map(t => {
      return {
        symbol: t.symbol,
        name: t.name,
        price: t.price || 0,
        cgId: t.cgId,
        imageUrl: t.imageUrl
      } as Token;
    });
  }

  async searchTokens(query: string, localMatches: TokenDefinition[]): Promise<TokenDefinition[]> {
    const marketData = await this.marketDataService.getMarketData();
    const searchResults = marketData.filter(token => {
      const lowerQuery = query.toLowerCase();
      return token.symbol.toLowerCase().includes(lowerQuery) || token.name.toLowerCase().includes(lowerQuery);
    });
    return [...localMatches, ...searchResults];
  }

  async getTokenHistory(symbol: string, days: number): Promise<HistoryPoint[]> {
    const endDate = new Date();
    const startDate = new Date();
    startDate.setDate(endDate.getDate() - days);

    const startTimestamp = Math.floor(startDate.getTime() / 1000);
    const endTimestamp = Math.floor(endDate.getTime() / 1000);

    const cgId = this.findTokenCgId(symbol);
    if (!cgId) return [];
    return this.http.get<any[]>(`${this.API_URL}/cg/history?cgId=${cgId}&from=${startTimestamp}&to=${endTimestamp}`)
        .toPromise().then(r => {
          return r.map(x => {
            return {
              time: x.time,
              value: x.value
            } as HistoryPoint;
          });
        });
  }

  private findTokenCgId(symbol: string): string | undefined {
    const token = this.tokens().find(t => t.symbol === symbol);
    return token?.cgId;
  }
}
