export class MathUtils {
  static average(data: number[]): number { return data.length === 0 ? 0 : data.reduce((a, b) => a + b, 0) / data.length; }
  static sma(data: number[], period: number): number | null {
    if (data.length < period) return null;
    return this.average(data.slice(-period));
  }
  static stdDev(data: number[]): number {
    if (data.length < 2) return 0;
    const avg = this.average(data);
    return Math.sqrt(this.average(data.map(v => Math.pow(v - avg, 2))));
  }
  static rsi(data: number[], period: number = 14): number | null {
    if (data.length < period + 1) return null;
    const changes = [];
    for (let i = 1; i < data.length; i++) changes.push(data[i] - data[i - 1]);
    if (changes.length < period) return null;
    const recent = changes.slice(-period);
    let gains = 0, losses = 0;
    recent.forEach(c => { if (c > 0) gains += c; else losses += Math.abs(c); });
    const avgGain = gains / period; const avgLoss = losses / period;
    if (avgLoss === 0) return avgGain === 0 ? 50 : 100;
    return 100 - (100 / (1 + (avgGain / avgLoss)));
  }
  static linearRegression(data: number[]): { m: number, b: number, r2: number } | null {
    const n = data.length;
    if (n < 2) return null;
    let sumX = 0, sumY = 0, sumXY = 0, sumXX = 0;
    for (let i = 0; i < n; i++) { sumX += i; sumY += data[i]; sumXY += i * data[i]; sumXX += i * i; }
    const m = (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);
    const b = (sumY - m * sumX) / n;
    let ss_tot = 0, ss_res = 0;
    const y_mean = this.average(data);
    for (let i = 0; i < n; i++) {
      const y_pred = m * i + b;
      ss_tot += (data[i] - y_mean) ** 2;
      ss_res += (data[i] - y_pred) ** 2;
    }
    return { m, b, r2: ss_tot === 0 ? 1 : 1 - (ss_res / ss_tot) };
  }
}

