import { Injectable, signal, computed, inject, effect } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime, PriceAlert, AlgoIconType, HistoryPoint } from './types';
import { MathUtils } from './math-utils';
import * as d3 from 'd3';
import { NotificationService } from './notification.service';
import { GeminiService } from './gemini.service';
import { UserPrefsService } from './user-prefs.service';

export interface PriceUpdateInfo { symbol: string; direction: 'up' | 'down' | 'same'; }

@Injectable({ providedIn: 'root' })
export class TokenStateService {
  private notificationService = inject(NotificationService);
  private geminiService = inject(GeminiService);
  private prefs = inject(UserPrefsService);
  private readonly SIGNAL_TTL = 30000;

  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });
  readonly selectedTokenSymbol = signal<string | null>(null);
  readonly priceAlerts = signal<Map<string, PriceAlert>>(new Map());
  readonly activeSignals = signal<Signal[]>([]);
  readonly btcToken = signal<Token | null>(null);
  readonly lastPriceUpdate = signal<PriceUpdateInfo | null>(null);
  private lastUpdateTimeout: any;

  constructor() {
    effect(() => { this.tokens(); this._updateSyncSignals(); });
  }

  readonly filteredSignals = computed(() => {
    const signals = this.activeSignals();
    const selected = this.selectedTokenSymbol();
    return selected ? signals.filter(s => s.tokenSymbol === selected) : signals;
  });

  readonly marketSummary = computed(() => {
    const summary = { advancing: 0, declining: 0, unchanged: 0 };
    this.tokens().forEach(token => {
      if (token.priceHistory.length < 2) { summary.unchanged++; return; }
      const curr = token.price, prev = token.priceHistory[token.priceHistory.length - 2].value;
      if (curr > prev) summary.advancing++; else if (curr < prev) summary.declining++; else summary.unchanged++;
    });
    return summary;
  });

  updateTokens(newTokens: Token[]) { this.tokens.set(newTokens); this.updateRegime(newTokens); }
  setBtcToken(token: Token | null) { this.btcToken.set(token); }

  updateBtcToken(summary: { price: number; change24h?: number }) {
    this.btcToken.update(current => {
      if (!current) return { symbol: 'BTC', name: 'Bitcoin', price: summary.price, change24h: summary.change24h ?? 0, priceHistory: [{ time: Date.now(), value: summary.price }], entryPrice: 0, volume: 0, yield: 0, volumeHistory: [], liquidityDepth: 0, cgId: 'bitcoin', imageUrl: 'https://assets.coingecko.com/coins/images/1/large/bitcoin.png' };
      return { ...current, price: summary.price, change24h: summary.change24h ?? current.change24h, priceHistory: [...current.priceHistory, { time: Date.now(), value: summary.price }].slice(-60) };
    });
  }

  batchUpdateTokenPrices(updates: Map<string, number>) {
    if (updates.has('BTC')) {
      const price = updates.get('BTC')!;
      this.btcToken.update(c => (!c || price === c.price) ? c : { ...c, price, priceHistory: [...c.priceHistory, { time: Date.now(), value: price }].slice(-60) });
      this.triggerPriceFlash({ symbol: 'BTC', direction: updates.get('BTC')! > (this.btcToken()?.price || 0) ? 'up' : 'down' });
      updates.delete('BTC');
    }
    if (updates.size === 0) return;
    this.tokens.update(current => {
      let changed = false;
      const updated = current.map(t => {
        if (updates.has(t.symbol)) {
          const np = updates.get(t.symbol)!;
          if (t.price !== np) {
            changed = true;
            this.triggerPriceFlash({ symbol: t.symbol, direction: np > t.price ? 'up' : 'down' });
            return { ...t, price: np, priceHistory: [...t.priceHistory, { time: Date.now(), value: np }].slice(-60) };
          }
        }
        return t;
      });
      return changed ? updated : current;
    });
  }

  private triggerPriceFlash(info: PriceUpdateInfo) {
    clearTimeout(this.lastUpdateTimeout);
    this.lastPriceUpdate.set(info);
    this.lastUpdateTimeout = setTimeout(() => this.lastPriceUpdate.set(null), 750);
  }

  toggleSelectedToken(symbol: string) { this.selectedTokenSymbol.update(c => c === symbol ? null : symbol); }
  clearSelection() { this.selectedTokenSymbol.set(null); }
  setPriceAlert(symbol: string, targetPrice: number, condition: 'ABOVE' | 'BELOW') {
    if (!targetPrice || targetPrice <= 0) { this.removePriceAlert(symbol); return; }
    this.priceAlerts.update(m => { const n = new Map(m); n.set(symbol, { targetPrice, condition }); return n; });
  }
  removePriceAlert(symbol: string) { this.priceAlerts.update(m => { const n = new Map(m); n.delete(symbol); return n; }); }

  private _updateSyncSignals(): void {
    const liveSignals: Signal[] = [];
    this.tokens().forEach(token => {
      if (!token) return;
      const signals = [
        this._generatePriceAlertSignal(token), this._generateBurstHunterSignal(token), this._generateGainLockSignal(token),
        this._generateHypePulseSignal(token), this._generateTrendVectorSignal(token), this._generateStableAnchorSignal(token),
        this._generateVenueShieldSignal(token), this._generateSupportBounceSignal(token), this._generateVolatilitySqueezeSignal(token),
        this._generateJerryReversionSignal(token)
      ].filter((s): s is Signal => s !== null);
      liveSignals.push(...signals);
    });

    const liveMap = new Map<string, Signal>();
    liveSignals.forEach(s => liveMap.set(`${s.tokenSymbol}:${s.type}`, s));

    this.activeSignals.update(current => {
      const refreshed = current.filter(s => s.type !== SignalType.NEWS_SPIKE).map(existing => {
        const key = `${existing.tokenSymbol}:${existing.type}`;
        const live = liveMap.get(key);
        if (live) { liveMap.delete(key); return { ...live, id: existing.id, timestamp: Date.now() }; }
        return existing;
      });

      const active = refreshed.filter(s => Date.now() - s.timestamp < this.SIGNAL_TTL);
      const newSigs = Array.from(liveMap.values()).map(s => ({ ...s, id: `${s.tokenSymbol}:${s.type}:${Date.now()}` }));

      newSigs.forEach(s => {
        if (s.type === SignalType.PRICE_ALERT && this.prefs.notificationsEnabled() && !this.prefs.disabledSignalTypesForNotifications().has(s.type)) {
          this.notificationService.show(`${s.tokenSymbol}: ${this.formatSignalType(s.type)}`, s.message, s.severity, this.getIconForSignal(s.type));
        }
      });

      const asyncSigs = current.filter(s => s.type === SignalType.NEWS_SPIKE);
      return [...active, ...newSigs, ...asyncSigs].sort((a, b) => b.timestamp - a.timestamp);
    });
  }

  async triggerAsyncSignalGeneration() {
    this.prefs.dataSourceMode() === 'SIMULATION' ? await this.runSimulatedNewsSpike() : await this.runLiveNewsSpikeCheck();
  }

  private async runSimulatedNewsSpike() {
    await new Promise(r => setTimeout(r, 300 + Math.random() * 400));
    const tokens = this.tokens();
    if (tokens.length === 0 || Math.random() > 0.15) return;
    const t = tokens[Math.floor(Math.random() * tokens.length)];
    if (this.activeSignals().some(s => s.tokenSymbol === t.symbol && s.type === SignalType.NEWS_SPIKE)) return;
    const isGood = Math.random() > 0.5;
    const signal = this._generateNewsSpikeSignal(t, `Unconfirmed reports suggest ${t.name} is involved in ${isGood ? "a strategic partnership" : "a potential exploit"}.`, '#');
    if (signal) this.addNewsSpikeSignal(signal);
  }

  private async runLiveNewsSpikeCheck() {
    const tokens = this.tokens();
    if (tokens.length === 0) return;
    const check = this.getRandomSubset(tokens, 3);
    for (const t of check) {
      if (this.activeSignals().some(s => s.tokenSymbol === t.symbol && s.type === SignalType.NEWS_SPIKE)) continue;
      const news = await this.geminiService.checkForNewsSpike(t);
      if (news?.isSignificantNews && news.articleTitle) {
        const signal = this._generateNewsSpikeSignal(t, news.articleTitle, news.articleUrl);
        if (signal) this.addNewsSpikeSignal(signal);
      }
    }
  }

  private addNewsSpikeSignal(signal: Signal) {
    this.activeSignals.update(c => {
      const activeAsync = c.filter(s => s.type === SignalType.NEWS_SPIKE && Date.now() - s.timestamp < this.SIGNAL_TTL);
      return [...c.filter(s => s.type !== SignalType.NEWS_SPIKE), ...activeAsync, signal].sort((a, b) => b.timestamp - a.timestamp);
    });
  }

  private updateRegime(tokens: Token[]) {
    if (tokens.length === 0) return;
    const avgVol = tokens.reduce((acc, t) => acc + (MathUtils.stdDev(t.priceHistory.slice(-10).map(p => p.value)) / MathUtils.average(t.priceHistory.slice(-10).map(p => p.value)) || 0), 0) / tokens.length;
    const upMoves = tokens.filter(t => t.priceHistory.length > 1 && t.price > t.priceHistory[t.priceHistory.length - 2].value).length;
    const corr = Math.abs((upMoves / tokens.length) - 0.5) * 2;
    let status: MarketRegime['status'] = 'NEUTRAL';
    if (avgVol > 0.015) status = 'VOLATILE'; else if (corr > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH'; else if (corr > 0.6) status = 'BEARISH';
    this.marketRegime.set({ status, volatility: avgVol, correlation: corr });
  }

  private _generateNewsSpikeSignal(token: Token, title: string, url?: string): Signal | null {
    return { id: `NEWS_SPIKE:${token.symbol}:${Date.now()}`, timestamp: Date.now(), type: SignalType.NEWS_SPIKE, tokenSymbol: token.symbol, message: `NEWS: ${title}`, severity: 'warning', confidence: 95, meta: { url, priceAtSignal: token.price } };
  }
  private _generatePriceAlertSignal(token: Token): Signal | null {
    const alert = this.priceAlerts().get(token.symbol);
    if (!alert || !((alert.condition === 'ABOVE' && token.price > alert.targetPrice) || (alert.condition === 'BELOW' && token.price < alert.targetPrice))) return null;
    return { id: `PRICE_ALERT:${token.symbol}`, timestamp: Date.now(), type: SignalType.PRICE_ALERT, tokenSymbol: token.symbol, message: `Price crossed ${alert.condition.toLowerCase()} alert at $${alert.targetPrice.toFixed(4)}.`, severity: 'warning', confidence: 100, meta: { priceAtSignal: token.price } };
  }
  private _generateBurstHunterSignal(token: Token): Signal | null {
    const ph = token.priceHistory.map(p => p.value), vh = token.volumeHistory.map(p => p.value);
    const smaVol20 = MathUtils.sma(vh, 20), sma20 = MathUtils.sma(ph, 20);
    if (!smaVol20 || ph.length < 3 || !sma20) return null;
    const lp = ph[ph.length - 2], plp = ph[ph.length - 3];
    if (!lp || !plp) return null;
    const change = (token.price - lp) / lp, ratio = token.volume / smaVol20;
    if (ratio > 3.5 && change > 0.02 && change > (lp - plp) / plp && token.price > sma20) {
      let conf = Math.min(Math.round((ratio / 10) * 100), 85) + 5;
      const ms = this.marketSummary();
      if ((ms.advancing / (ms.advancing + ms.declining || 1)) > 0.6) conf = Math.min(conf + 10, 99);
      return { id: `BURST:${token.symbol}`, timestamp: Date.now(), type: SignalType.BURST_HUNTER, tokenSymbol: token.symbol, message: `Macro-Confirmed Volume Burst: ${ratio.toFixed(1)}x normal.`, severity: 'success', confidence: conf, meta: { priceAtSignal: token.price } };
    }
    return null;
  }
  private _generateGainLockSignal(token: Token): Signal | null {
    if (!token || token.entryPrice <= 0) return null;
    const profit = (token.price - token.entryPrice) / token.entryPrice;
    const ph = token.priceHistory.map(p => p.value);
    const sma10 = MathUtils.sma(ph, 10), sma50 = MathUtils.sma(ph, 50);
    if (profit > 1.0 && sma10 && sma50 && sma10 < sma50) {
      return { id: `LOCK:${token.symbol}`, timestamp: Date.now(), type: SignalType.GAIN_LOCK, tokenSymbol: token.symbol, message: `Take Profit: +${(profit * 100).toFixed(0)}% gain with Momentum Death Cross.`, severity: 'warning', confidence: 90, meta: { priceAtSignal: token.price } };
    }
    return null;
  }
  private _generateHypePulseSignal(token: Token): Signal | null {
    const rsi = MathUtils.rsi(token.priceHistory.map(p => p.value), 14);
    if (!rsi) return null;
    const regime = this.marketRegime().status;
    const thresh = regime === 'BULLISH' ? 80 : regime === 'BEARISH' ? 60 : 70;
    if (rsi > thresh) {
      return { id: `HYPE_BUY:${token.symbol}`, timestamp: Date.now(), type: SignalType.HYPE_PULSE_BUY, tokenSymbol: token.symbol, message: `Overbought (RSI > ${thresh}): ${rsi.toFixed(0)}.`, severity: 'info', confidence: Math.min(Math.round(((rsi - thresh) / (100 - thresh)) * 100) + 50, 95), meta: { priceAtSignal: token.price } };
    }
    return null;
  }
  private _generateTrendVectorSignal(token: Token): Signal | null {
    const ph = token.priceHistory.map(p => p.value);
    const reg = MathUtils.linearRegression(ph.slice(-15)), sma50 = MathUtils.sma(ph, 50), vol = this.marketRegime().volatility;
    const r2Thresh = vol > 0.015 ? 0.75 : 0.60;
    if (reg && sma50 && reg.r2 > r2Thresh && vol < 0.025) {
      const slope = reg.m / token.price;
      if (Math.abs(slope) > 0.005) {
        const dir = slope > 0 ? 'UP' : 'DOWN';
        if ((dir === 'UP' && token.price > sma50) || (dir === 'DOWN' && token.price < sma50)) {
          return { id: `VECTOR:${token.symbol}`, timestamp: Date.now(), type: SignalType.TREND_VECTOR, tokenSymbol: token.symbol, message: `Strong Trend Vector (R²=${reg.r2.toFixed(2)}): Projecting ${(token.price + (reg.m * 5)).toFixed(2)}`, severity: dir === 'UP' ? 'success' : 'danger', confidence: Math.min(85 + Math.round(((reg.r2 - r2Thresh) / (1 - r2Thresh)) * 14), 99), meta: { projectedPrice: token.price + (reg.m * 5), priceAtSignal: token.price } };
        }
      }
    }
    return null;
  }
  private _generateStableAnchorSignal(token: Token): Signal | null {
    const vol = MathUtils.stdDev(token.priceHistory.slice(-20).map(p => p.value)) / token.price;
    if (vol < 0.05 && token.yield > 5.0) return { id: `ANCHOR:${token.symbol}`, timestamp: Date.now(), type: SignalType.STABLE_ANCHOR, tokenSymbol: token.symbol, message: `Yield Safe Haven: ${token.yield.toFixed(2)}% APY.`, severity: 'success', confidence: 85, meta: { priceAtSignal: token.price } };
    return null;
  }
  private _generateVenueShieldSignal(token: Token): Signal | null {
    if (token.liquidityDepth < 1000000) return { id: `VENUE:${token.symbol}`, timestamp: Date.now(), type: SignalType.VENUE_SHIELD, tokenSymbol: token.symbol, message: `High Slippage Risk: Low Liquidity.`, severity: 'danger', confidence: 100, meta: { priceAtSignal: token.price } };
    return null;
  }
  private _generateSupportBounceSignal(token: Token): Signal | null {
    const ph = token.priceHistory.map(p => p.value), vh = token.volumeHistory.map(p => p.value), rsi = MathUtils.rsi(ph, 14);
    if (ph.length > 20 && vh.length > 2 && rsi && rsi < 65) {
      const recent = ph.slice(-20), min = d3.min(recent) || 0, prev = ph[ph.length - 2];
      if (token.price > prev && (token.price - min) / min < 0.05 && token.price > min && token.volume > vh[vh.length - 2]) {
        return { id: `SUPPORT_BOUNCE:${token.symbol}`, timestamp: Date.now(), type: SignalType.SUPPORT_BOUNCE, tokenSymbol: token.symbol, message: `Volume-Confirmed Bounce off 20-period low.`, severity: 'success', confidence: 75, meta: { priceAtSignal: token.price } };
      }
    }
    return null;
  }
  private _generateVolatilitySqueezeSignal(token: Token): Signal | null {
    const ph = token.priceHistory.map(p => p.value), rsi = MathUtils.rsi(ph, 14), sma20 = MathUtils.sma(ph, 20);
    if (ph.length > 20 && rsi && rsi > 40 && rsi < 60) {
      const bw = ((sma20! + 2 * MathUtils.stdDev(ph.slice(-20))) - (sma20! - 2 * MathUtils.stdDev(ph.slice(-20)))) / sma20!;
      if (bw < 0.025) return { id: `SQUEEZE:${token.symbol}`, timestamp: Date.now(), type: SignalType.VOLATILITY_SQUEEZE, tokenSymbol: token.symbol, message: `High-Compression Squeeze: (Bandwidth ${(bw * 100).toFixed(2)}%).`, severity: 'warning', confidence: Math.min(80 + Math.round(((0.025 - bw) / 0.025) * 19), 99), meta: { priceAtSignal: token.price } };
    }
    return null;
  }
  private _generateJerryReversionSignal(token: Token): Signal | null {
    const r = this.marketRegime().status, ph = token.priceHistory.map(p => p.value);
    if ((r === 'NEUTRAL' || r === 'VOLATILE') && ph.length > 20) {
      const sma20 = MathUtils.sma(ph, 20), std = MathUtils.stdDev(ph.slice(-20)), prev = ph[ph.length - 2], pprev = ph[ph.length - 3];
      if (sma20 && std && prev && pprev) {
        const dev = (sma20 - token.price) / sma20;
        if (dev > 0.05 && (std / token.price) < 0.10 && token.price > prev && prev > pprev) {
          let conf = 75; if (dev > 0.1) conf += 10; if ((std / token.price) < 0.05) conf += 10;
          return { id: `JERRY:${token.symbol}`, timestamp: Date.now(), type: SignalType.JERRY_REVERSION, tokenSymbol: token.symbol, message: `Confirmed Reversion: ${(dev * 100).toFixed(0)}% below mean.`, severity: 'success', confidence: Math.min(conf, 99), meta: { priceAtSignal: token.price } };
        }
      }
    }
    return null;
  }

  private getRandomSubset<T>(arr: T[], size: number): T[] { return [...arr].sort(() => 0.5 - Math.random()).slice(0, Math.min(size, arr.length)); }
  private formatSignalType(type: SignalType): string { return type.replace(/_/g, ' ').replace('BUY', '').replace('SELL', '').trim(); }
  private getIconForSignal(type: SignalType): AlgoIconType {
    if (type === SignalType.HYPE_PULSE_BUY || type === SignalType.HYPE_PULSE_SELL) return 'HYPE_PULSE';
    if (type === SignalType.PRICE_ALERT) return 'GAIN_LOCK';
    if (type === SignalType.SUPPORT_BOUNCE) return 'PATTERN_SCANNER';
    return type as AlgoIconType;
  }
}

