import { Injectable, inject } from '@angular/core';
import { GoogleGenAI, GenerateContentConfig } from "@google/genai";
import { Token, MarketRegime, Signal, GroundingChunk, HistoryPoint } from './types';
import { MathUtils } from './math-utils';
import { NotificationService } from './notification.service';

interface NewsSpikeResponse { isSignificantNews: boolean; articleTitle?: string; articleUrl?: string; }

@Injectable({ providedIn: 'root' })
export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private isAvailable = false;
  private notificationService = inject(NotificationService);

  constructor() {
    const key = process.env['API_KEY'];
    if (key) { this.ai = new GoogleGenAI({ apiKey: key }); this.isAvailable = true; } 
    else console.warn('KESTREL: API_KEY not found. AI features disabled.');
  }

  async generateMarketNarrative(tokens: Token[], regime: MarketRegime, signals: Signal[], useGrounding: boolean): Promise<{ narrative: string; sources: GroundingChunk[] }> {
    if (!this.isAvailable || !this.ai) return { narrative: "AI MODULE OFFLINE. KEY MISSING.", sources: [] };
    const prompt = `You are Kestrel, a crypto market intelligence system. Regime: ${regime.status} (Vol: ${regime.volatility.toFixed(2)}). Snapshot: ${tokens.map(t => `${t.symbol}: $${t.price.toFixed(4)}`).join(', ')}. Signals: ${signals.slice(0, 5).map(s => `[${s.type}] ${s.tokenSymbol}: ${s.message}`).join('; ')}. Generate a concise, 2-sentence market narrative. Style: Cyberpunk, Concise, Analytical.`;
    const config: GenerateContentConfig = useGrounding ? { tools: [{ googleSearch: {} }] } : {};
    try {
      const response = await this.ai.models.generateContent({ model: 'gemini-2.5-flash', contents: prompt, config });
      return { narrative: response.text || "NO NARRATIVE", sources: (response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[]) || [] };
    } catch (e) {
      console.error('Gemini Error', e); this.notificationService.show('AI Narrative Failed', 'AI Module Unavailable', 'danger', 'INFO');
      return { narrative: "SYSTEM ERROR: AI UNREACHABLE", sources: [] };
    }
  }

  async checkForNewsSpike(token: Token): Promise<NewsSpikeResponse | null> {
    if (!this.isAvailable || !this.ai) return null;
    const prompt = `Search for significant news (partnerships, hacks, regs) last 24h for '${token.name} (${token.symbol})'. Respond JSON: { "isSignificantNews": boolean, "articleTitle"?: string, "articleUrl"?: string }.`;
    try {
      const response = await this.ai.models.generateContent({ model: 'gemini-2.5-flash', contents: prompt, config: { tools: [{ googleSearch: {} }] } });
      const jsonText = response.text?.trim();
      if (jsonText) {
        const match = jsonText.match(/\{[\s\S]*\}/);
        if (match) return JSON.parse(match[0]) as NewsSpikeResponse;
      }
      return null;
    } catch (e) { console.error('News Check Failed', e); return null; }
  }

  async analyzeSignalContext(signal: Signal, token: Token): Promise<string> {
    if (!this.isAvailable || !this.ai) return "AI OFFLINE";
    const prompt = `Analyze signal ${signal.type} for ${token.tokenSymbol}. Msg: ${signal.message}. Conf: ${signal.confidence}. Price: ${token.price}. RSI: ${MathUtils.rsi(token.priceHistory.map(p=>p.value), 14)?.toFixed(2)}. VolHist: [${token.volumeHistory.slice(-20).map(v=>Math.round(v.value)).join(',')}]. Provide 1-sentence tactical prediction. Under 20 words. Style: Military.`;
    try {
      const response = await this.ai.models.generateContent({ model: 'gemini-2.5-flash', contents: prompt });
      return response.text || "ANALYSIS FAILED";
    } catch (e) { this.notificationService.show('AI Analysis Failed', 'AI Module Error', 'danger', 'INFO'); return "AI ERROR"; }
  }
}

