export class IntelPanelComponent {
  private local = inject(LocalNarrativeService); private state = inject(TokenStateService); public prefs = inject(UserPrefsService); private gemini = inject(GeminiService);
  narrative = signal(''); sources = signal<GroundingChunk[]>([]); loading = signal(false);
  constructor() { this.refreshIntel(); }
  async refreshIntel() {
    if (this.loading()) return;
    this.loading.set(true); this.narrative.set(''); this.sources.set([]);
