import { Component, input, signal, inject, computed, output, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Signal, SignalType, Token, AlgoIconType } from '../services/types';
import { GeminiService } from '../services/gemini.service';
import { TokenStateService } from '../services/token-state.service';
import { UserPrefsService } from '../services/user-prefs.service';
import { AlgorithmIconComponent } from './algorithm-icon.component';

type FilterType = 'ALL' | 'HIGH_CONFIDENCE' | 'OPPORTUNITY' | 'RISK' | 'PREDICTION';

@Component({
  selector: 'app-signal-feed',
  standalone: true,
  imports: [CommonModule, AlgorithmIconComponent],
  template: `
    <div class="flex flex-col h-full bg-white dark:bg-slate-925 rounded-lg overflow-hidden">
      <div class="flex items-center gap-2 p-2 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50 overflow-x-auto custom-scrollbar">
        @for(f of filters; track f.id) {
          <button (click)="setFilter(f.id)" class="px-3 py-1 text-[10px] font-bold rounded transition-colors border whitespace-nowrap" [class]="filter() === f.id ? f.classes : 'text-slate-500 border-slate-300 dark:border-slate-700'">{{ f.label }}</button>
        }
      </div>
      <div class="flex-grow overflow-y-auto custom-scrollbar p-2 space-y-2">
        @for (sig of displayedSignals(); track sig.id) {
          <div class="group border border-slate-200 dark:border-slate-800 rounded bg-slate-50 dark:bg-slate-900/40 p-3 shadow-sm signal-enter-active"
            [class.new-signal-highlight]="newSignalIds().has(sig.id)"
            [class.border-l-4]="true" [class.border-l-green-500]="sig.severity === 'success'" [class.border-l-yellow-500]="sig.severity === 'warning'" [class.border-l-red-500]="sig.severity === 'danger'" [class.border-l-blue-500]="sig.severity === 'info'" [class.border-l-slate-400]="sig.type === 'JERRY_REVERSION'">
            <div class="flex justify-between items-center mb-2">
              <div class="flex items-center gap-4">
                <div class="flex items-center gap-1.5 text-[10px] font-bold px-1.5 py-0.5 rounded text-white dark:text-black uppercase tracking-wider"
                  [class.bg-green-600]="sig.severity === 'success' && sig.type !== 'JERRY_REVERSION'" [class.dark:bg-green-500]="sig.severity === 'success' && sig.type !== 'JERRY_REVERSION'"
                  [class.bg-yellow-600]="sig.severity === 'warning'" [class.dark:bg-yellow-500]="sig.severity === 'warning'"
                  [class.bg-red-600]="sig.severity === 'danger'" [class.dark:bg-red-500]="sig.severity === 'danger'"
                  [class.bg-blue-600]="sig.severity === 'info'" [class.dark:bg-blue-500]="sig.severity === 'info'"
                  [class.bg-slate-500]="sig.type === 'JERRY_REVERSION'" [class.dark:bg-slate-400]="sig.type === 'JERRY_REVERSION'">
                  <app-algorithm-icon [name]="getIconForSignal(sig.type)" class="w-3 h-3" />
                  <span>{{ formatType(sig.type) }}</span>
                </div>
                <button (click)="inspect.emit(sig.tokenSymbol)" class="text-lg font-bold text-green-600 dark:text-teal-400 font-mono tracking-tighter">{{ sig.tokenSymbol }}</button>
              </div>
              <span class="text-[10px] text-slate-400 font-mono">{{ sig.timestamp | date:'HH:mm:ss' }}</span>
            </div>
            <div class="text-xs font-mono text-slate-600 dark:text-slate-400 mb-3 leading-relaxed">{{ sig.message }}</div>
            <div class="flex items-center gap-2 mb-2">
                <div class="flex items-center gap-0.5">
                  @for (i of segments; track i) { <div class="w-1.5 h-4 rounded-sm" [class]="getSegmentColor(sig.confidence, i)"></div> }
                </div>
                <span class="text-[10px] text-slate-500 dark:text-slate-400 font-mono">{{ sig.confidence }}%</span>
            </div>
            <div class="flex items-start gap-2 min-h-[20px] mt-2 border-t border-slate-100 dark:border-slate-800/50 pt-2">
