                 <button (click)="analyze(sig)" class="text-[10px] font-bold text-blue-600 dark:text-blue-400 hover:underline flex items-center gap-1 opacity-60 group-hover:opacity-100">[AI_TACTICAL_ANALYSIS]</button>
               }
               @if (analyzingState().has(sig.id)) { <span class="text-[10px] text-slate-400 animate-pulse">COMPUTING...</span> }
               @if (analysisMap().get(sig.id); as result) {
                 <div class="bg-slate-100 dark:bg-slate-800/80 p-2 rounded w-full border border-slate-200 dark:border-slate-700">
                    <div class="flex justify-between items-start mb-1"><span class="text-[10px] text-blue-600 dark:text-blue-400 font-bold">GEMINI TACTICAL:</span><button (click)="clearAnalysis(sig.id)" class="text-[10px] text-slate-400">x</button></div>
                    <p class="text-[11px] text-slate-700 dark:text-slate-300 font-mono leading-tight">{{ result }}</p>
                 </div>
               }
            </div>
          </div>
        } @empty {
          <div class="flex flex-col items-center justify-center h-48 text-slate-400 dark:text-slate-600"><div class="text-xs font-mono">NO SIGNALS MATCHING FILTER</div></div>
        }
