})
export class SignalFeedComponent {
  signals = input.required<Signal[]>(); tokens = input.required<Token[]>(); inspect = output<string>();
  private gemini = inject(GeminiService); filter = signal<FilterType>('ALL');
  analysisMap = signal<Map<string, string>>(new Map()); analyzingState = signal<Set<string>>(new Set());
  private newSignalIds = signal<Set<string>>(new Set()); private trackedSignalIds = new Set<string>();
  readonly segments = Array.from({length: 10}, (_, i) => i);
  tokenMap = computed(() => new Map(this.tokens().map(t => [t.symbol, t])));
  readonly filters = [
    { id: 'ALL', label: 'ALL', classes: 'bg-slate-200 dark:bg-slate-700' },
    { id: 'HIGH_CONFIDENCE', label: 'HIGH CONFIDENCE', classes: 'bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400' },
    { id: 'OPPORTUNITY', label: 'OPPORTUNITY', classes: 'bg-green-100 dark:bg-teal-900/30 text-green-600 dark:text-teal-400' },
    { id: 'RISK', label: 'RISK ALERT', classes: 'bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400' },
    { id: 'PREDICTION', label: 'PREDICTIONS', classes: 'bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400' }
  ];

  constructor() {
    effect(() => {
      const current = this.signals(), newIds: string[] = [];
      for (const sig of current) if (!this.trackedSignalIds.has(sig.id)) { newIds.push(sig.id); this.trackedSignalIds.add(sig.id); }
      if (newIds.length > 0) {
        this.newSignalIds.update(c => { const n = new Set(c); newIds.forEach(id => n.add(id)); return n; });
        setTimeout(() => this.newSignalIds.update(c => { const n = new Set(c); newIds.forEach(id => n.delete(id)); return n; }), 6000);
      }
    });
  }
  displayedSignals = computed(() => {
    const s = this.signals();
    switch (this.filter()) {
      case 'HIGH_CONFIDENCE': return s.filter(x => x.confidence >= 80);
      case 'OPPORTUNITY': return s.filter(x => x.severity === 'success' || x.severity === 'info');
      case 'RISK': return s.filter(x => x.severity === 'warning' || x.severity === 'danger');
      case 'PREDICTION': return s.filter(x => [SignalType.TREND_VECTOR, SignalType.SUPPORT_BOUNCE, SignalType.VOLATILITY_SQUEEZE, SignalType.JERRY_REVERSION].includes(x.type));
      default: return s;
    }
  });
  getSegmentColor(conf: number, i: number) { return conf >= (i + 1) * 10 ? (conf < 50 ? 'bg-yellow-500' : conf <= 80 ? 'bg-blue-500' : 'bg-green-500 dark:bg-teal-400') : 'bg-slate-200 dark:bg-slate-800'; }
  setFilter(f: any) { this.filter.set(f); }
  formatType(t: string) { return t.replace(/_/g, ' ').replace('BUY', '').replace('SELL', ''); }
  getIconForSignal(type: SignalType): AlgoIconType { if (type.includes('HYPE')) return 'HYPE_PULSE'; if (type === SignalType.PRICE_ALERT) return 'GAIN_LOCK'; if (type === SignalType.SUPPORT_BOUNCE) return 'PATTERN_SCANNER'; return type as AlgoIconType; }
  async analyze(sig: Signal) {
    const t = this.tokenMap().get(sig.tokenSymbol); if (!t) return;
    this.analyzingState.update(s => new Set(s).add(sig.id));
    try { const a = await this.gemini.analyzeSignalContext(sig, t); this.analysisMap.update(m => new Map(m).set(sig.id, a)); } finally { this.analyzingState.update(s => { const n = new Set(s); n.delete(sig.id); return n; }); }
  }
  clearAnalysis(id: string) { this.analysisMap.update(m => { const n = new Map(m); n.delete(id); return n; }); }
}

