import { Injectable, inject, signal, effect } from '@angular/core';
import { TokenStateService } from './token-state.service';
import { Signal, SignalType, PerformanceData } from './types';

interface PendingSignal { signal: Signal; entryPrice: number; startTick: number; }

@Injectable({ providedIn: 'root' })
export class PerformanceTrackerService {
    private tokenState = inject(TokenStateService);
    readonly stats = signal<Map<SignalType, PerformanceData>>(new Map());
    private pendingSignals = new Map<string, PendingSignal>();
    private processedSignalIds = new Set<string>();
    private tickCounter = 0;
    private readonly RESOLUTION_TICKS = 5;

    constructor() {
        effect(() => {
            this.tokenState.tokens(); this.tickCounter++;
            this.processNewSignals(this.tokenState.activeSignals());
            this.resolvePendingSignals();
        });
    }

    private processNewSignals(signals: Signal[]) {
        const trackable = signals.filter(s => this.isTrackable(s));
        for (const sig of trackable) {
            if (!this.processedSignalIds.has(sig.id)) {
                const token = this.tokenState.tokens().find(t => t.symbol === sig.tokenSymbol);
                if (token) {
                    this.pendingSignals.set(sig.id, { signal: sig, entryPrice: token.price, startTick: this.tickCounter });
                    this.processedSignalIds.add(sig.id);
                }
            }
        }
    }

    private resolvePendingSignals() {
        if (this.pendingSignals.size === 0) return;
        for (const [id, pending] of this.pendingSignals.entries()) {
            if (this.tickCounter >= pending.startTick + this.RESOLUTION_TICKS) {
                const token = this.tokenState.tokens().find(t => t.symbol === pending.signal.tokenSymbol);
                if (token) this.calculateOutcome(pending, token.price);
                this.pendingSignals.delete(id);
            }
        }
    }

    private calculateOutcome(pending: PendingSignal, exitPrice: number) {
        const { signal, entryPrice } = pending;
        if (entryPrice === 0) return;
        const returnPercent = ((exitPrice - entryPrice) / entryPrice) * 100;
        const isWin = returnPercent > 0.05;
        this.stats.update(current => {
            const n = new Map(current);
            const ex = n.get(signal.type) || this.getInitialData();
            n.set(signal.type, { totalSignals: ex.totalSignals + 1, wins: ex.wins + (isWin?1:0), losses: ex.losses + (isWin?0:1), winRate: ((ex.wins + (isWin?1:0)) / (ex.totalSignals + 1)) * 100, totalPnlPercent: ex.totalPnlPercent + returnPercent, averageReturn: (ex.totalPnlPercent + returnPercent) / (ex.totalSignals + 1) });
            return n;
        });
    }

    resetStats() { this.stats.set(new Map()); this.pendingSignals.clear(); this.processedSignalIds.clear(); }
    private isTrackable(s: Signal): boolean {
        if (s.type === SignalType.TREND_VECTOR && s.severity === 'danger') return false;
        return [SignalType.BURST_HUNTER, SignalType.SUPPORT_BOUNCE, SignalType.JERRY_REVERSION, SignalType.VOLATILITY_SQUEEZE, SignalType.TREND_VECTOR, SignalType.NEWS_SPIKE].includes(s.type);
    }
    private getInitialData(): PerformanceData { return { totalSignals: 0, wins: 0, losses: 0, winRate: 0, totalPnlPercent: 0, averageReturn: 0 }; }
}
